import{_ as t,a,b as d}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as i,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"เพิ่ม Cloudflare R2 Channel","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/upload/cloudflare-r2.md","filePath":"th-TH/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),n={name:"th-TH/upload/cloudflare-r2.md"};function c(u,e,h,s,b,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="เพิ่ม-cloudflare-r2-channel" tabindex="-1">เพิ่ม Cloudflare R2 Channel <a class="header-anchor" href="#เพิ่ม-cloudflare-r2-channel" aria-label="Permalink to &quot;เพิ่ม Cloudflare R2 Channel&quot;">​</a></h1><h2 id="เหมาะกับกรณีไหน" tabindex="-1">เหมาะกับกรณีไหน <a class="header-anchor" href="#เหมาะกับกรณีไหน" aria-label="Permalink to &quot;เหมาะกับกรณีไหน&quot;">​</a></h2><p>ใช้ Cloudflare R2 เมื่อ:</p><ul><li>ImgBed site ของคุณ deploy อยู่บน Cloudflare อยู่แล้ว และต้องการเก็บ files ใน R2 bucket ภายใต้ Cloudflare account เดียวกัน</li><li>ไม่ต้องการตั้งค่า S3 endpoint, access key และ secret key แยกต่างหาก</li><li>ต้องการให้การอ่านและเขียนผ่าน Worker หรือ Pages R2 binding โดยตั้งค่าน้อยที่สุด</li></ul><p>สรุปสั้น ๆ:</p><p>R2 channel ไม่ได้สร้างด้วยตัวเองใน ImgBed admin panel ก่อนอื่นต้อง bind R2 bucket เข้ากับ Cloudflare project และ binding variable name ต้องเป็น <code>img_r2</code></p><h2 id="สิ่งที่ต้องเตรียมก่อนเริ่ม" tabindex="-1">สิ่งที่ต้องเตรียมก่อนเริ่ม <a class="header-anchor" href="#สิ่งที่ต้องเตรียมก่อนเริ่ม" aria-label="Permalink to &quot;สิ่งที่ต้องเตรียมก่อนเริ่ม&quot;">​</a></h2><ul><li>Cloudflare account</li><li>R2 bucket ที่มีอยู่แล้ว</li><li>สิทธิ์จัดการ Cloudflare project ที่ deploy ImgBed อยู่</li></ul><h2 id="configure-ใน-cloudflare" tabindex="-1">Configure ใน Cloudflare <a class="header-anchor" href="#configure-ใน-cloudflare" aria-label="Permalink to &quot;Configure ใน Cloudflare&quot;">​</a></h2><h3 id="_1-สร้าง-r2-bucket" tabindex="-1">1. สร้าง R2 Bucket <a class="header-anchor" href="#_1-สร้าง-r2-bucket" aria-label="Permalink to &quot;1. สร้าง R2 Bucket&quot;">​</a></h3><ol><li>Log in เข้า Cloudflare Dashboard</li><li>เปิด <code>R2 Object Storage</code></li><li>คลิก Create bucket</li><li>เลือก bucket name เช่น <code>imgbed</code></li></ol><p>Bucket นี้คือที่เก็บ uploaded files</p><p><img src="'+t+'" alt="Create an R2 bucket" loading="lazy"></p><h3 id="_2-bind-bucket-เข้ากับ-imgbed-project" tabindex="-1">2. Bind Bucket เข้ากับ ImgBed Project <a class="header-anchor" href="#_2-bind-bucket-เข้ากับ-imgbed-project" aria-label="Permalink to &quot;2. Bind Bucket เข้ากับ ImgBed Project&quot;">​</a></h3><p>เลือกตำแหน่ง binding ตาม deployment type:</p><table tabindex="0"><thead><tr><th>Deployment Type</th><th>Binding Location</th></tr></thead><tbody><tr><td>Pages</td><td>Current Pages project -&gt; Settings -&gt; Functions -&gt; R2 bucket bindings</td></tr><tr><td>Worker</td><td>Current Worker -&gt; Settings -&gt; Bindings -&gt; R2 bucket bindings</td></tr></tbody></table><p>ตอนเพิ่ม binding ให้ใส่ field สำคัญดังนี้:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Variable name</td><td><code>img_r2</code></td></tr><tr><td>R2 bucket</td><td>เลือก bucket ที่สร้างไว้</td></tr></tbody></table><p>Variable name ต้องเป็น <code>img_r2</code> แบบตรงตัว การ upload, read และ delete R2 files อาศัย binding name นี้ทั้งหมด</p><h3 id="_3-redeploy-project" tabindex="-1">3. Redeploy Project <a class="header-anchor" href="#_3-redeploy-project" aria-label="Permalink to &quot;3. Redeploy Project&quot;">​</a></h3><p>หลัง save binding แล้ว ให้ redeploy ImgBed เพื่อให้ Worker หรือ Pages runtime เข้าถึง <code>img_r2</code> ได้</p><h2 id="สิ่งที่จะเห็นใน-imgbed" tabindex="-1">สิ่งที่จะเห็นใน ImgBed <a class="header-anchor" href="#สิ่งที่จะเห็นใน-imgbed" aria-label="Permalink to &quot;สิ่งที่จะเห็นใน ImgBed&quot;">​</a></h2><p>เมื่อ R2 binding พร้อมใช้งานแล้ว ให้เปิด:</p><ol><li>System Settings</li><li>Upload Settings</li><li><code>Cloudflare R2</code> channel</li></ol><p>System จะสร้าง fixed channel ให้อัตโนมัติ:</p><table tabindex="0"><thead><tr><th>Field</th><th>Fixed Value</th></tr></thead><tbody><tr><td>Channel name</td><td><code>Cloudflare R2</code></td></tr><tr><td>Channel type</td><td><code>cfr2</code></td></tr><tr><td>Storage mode</td><td><code>binding</code></td></tr><tr><td>Configuration source</td><td>Environment binding</td></tr></tbody></table><p>นี่คือ fixed binding channel ไม่ต้องคลิก Add Channel เพื่อสร้าง และลบเหมือน regular channel ไม่ได้</p><h2 id="fields-ที่แก้ไขได้ใน-admin-panel" tabindex="-1">Fields ที่แก้ไขได้ใน Admin Panel <a class="header-anchor" href="#fields-ที่แก้ไขได้ใน-admin-panel" aria-label="Permalink to &quot;Fields ที่แก้ไขได้ใน Admin Panel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>ใช้ทำอะไร</th><th>Required</th></tr></thead><tbody><tr><td>Enable channel</td><td>ควบคุมว่า R2 จะเข้าร่วม upload selection หรือไม่</td><td>Yes</td></tr><tr><td>Account ID</td><td>ใช้เมื่อเปิด quota limits และต้อง query official R2 usage</td><td>Recommended เมื่อเปิด quota limits</td></tr><tr><td>Bucket name</td><td>ใช้เมื่อเปิด quota limits และต้อง query official R2 usage</td><td>Recommended เมื่อเปิด quota limits</td></tr><tr><td>Quota limit</td><td>ควบคุมว่า R2 channel นี้จะเข้าร่วม upload selection ตาม capacity หรือไม่</td><td>No</td></tr><tr><td>Threshold</td><td>หยุดเขียนเข้า channel นี้เมื่อ usage ถึง percentage ที่กำหนด</td><td>Required เมื่อเปิด quota limits</td></tr></tbody></table><p>คุณ copy Account ID ได้จาก account information panel ใน Cloudflare dashboard ใส่เฉพาะเมื่ออยากให้ ImgBed query และ enforce R2 quota usage</p><p><img src="'+a+'" alt="Get the Account ID" loading="lazy"></p><h2 id="ขั้นตอนตั้งค่า" tabindex="-1">ขั้นตอนตั้งค่า <a class="header-anchor" href="#ขั้นตอนตั้งค่า" aria-label="Permalink to &quot;ขั้นตอนตั้งค่า&quot;">​</a></h2><ol><li>สร้าง R2 bucket ใน Cloudflare</li><li>เปิด Cloudflare settings ของ ImgBed project</li><li>เพิ่ม R2 bucket binding</li><li>ตั้ง <code>Variable name</code> เป็น <code>img_r2</code></li><li>เลือก R2 bucket ที่สร้างไว้</li><li>Save binding แล้ว redeploy ImgBed</li><li>กลับไปที่ ImgBed -&gt; System Settings -&gt; Upload Settings</li><li>ตรวจสอบว่า <code>Cloudflare R2</code> channel แสดงขึ้นและ enabled อยู่</li></ol><p>ถ้าต้องการให้ R2 เข้าร่วม upload selection ตาม capacity ให้เปิด quota limit แล้วใส่ Account ID, bucket name, quota limit และ threshold ก่อน save</p><p><img src="'+d+'" alt="Configure quota limits" loading="lazy"></p><h2 id="วิธีตรวจสอบ" tabindex="-1">วิธีตรวจสอบ <a class="header-anchor" href="#วิธีตรวจสอบ" aria-label="Permalink to &quot;วิธีตรวจสอบ&quot;">​</a></h2><ul><li>เห็น fixed <code>Cloudflare R2</code> channel ใน Upload Settings</li><li>Channel card แสดงว่า enabled</li><li>Upload small test file ได้สำเร็จ และ returned link เปิดได้ปกติ</li><li>ถ้าเปิด file แล้วขึ้น <code>R2 database binding is not configured</code> แปลว่า runtime ยังไม่ได้รับ <code>img_r2</code> binding ให้ตรวจ binding name ใน Cloudflare แล้ว redeploy project</li></ul>',37)])])}const k=l(n,[["render",c]]);export{f as __pageData,k as default};
